const warmLeads = $input.all().map(i => i.json);
const stats = $('get-stats').first().json;

const ov = stats.pipeline_overview || {};
const ef = stats.email_funnel || {};
const roi = stats.roi || {};
const breakdown = ov.breakdown || {};

const today = new Date().toLocaleDateString('en-US', {
  weekday: 'short', year: 'numeric', month: 'short', day: 'numeric'
});
const warmCount = warmLeads.length;
const openRate = ef.open_rate || 0;

const subject = `nrankai daily — ${today} | ${warmCount} warm leads | ${openRate}% open rate`;

const top5 = warmLeads.slice(0, 5);
const warmRowsHtml = top5.map(l => {
  const city = [l.location_city, l.location_state].filter(Boolean).join(', ') || '—';
  return `<tr style="border-top:1px solid #334155;">
    <td style="padding:7px 10px;font-weight:600;color:#e2e8f0;">${l.business_name || ''}</td>
    <td style="padding:7px 10px;color:#94a3b8;">${city}</td>
    <td style="padding:7px 10px;text-align:right;color:#f59e0b;font-weight:700;">${l.open_count || 0}</td>
  </tr>`;
}).join('');

const warmTable = top5.length > 0
  ? `<table style="width:100%;border-collapse:collapse;">
      <tr style="color:#64748b;font-size:11px;text-transform:uppercase;">
        <th style="text-align:left;padding:4px 10px;">Business</th>
        <th style="text-align:left;padding:4px 10px;">City</th>
        <th style="text-align:right;padding:4px 10px;">Opens</th>
      </tr>
      ${warmRowsHtml}
    </table>`
  : '<p style="color:#10b981;font-weight:600;margin:0;">Inbox clear — no warm leads pending.</p>';

const kpis = [
  { label: 'Total Prospects', value: ov.total_prospects || 0, color: '#e2e8f0' },
  { label: 'Emails Sent', value: ef.sent || 0, color: '#e2e8f0' },
  { label: 'Open Rate', value: openRate + '%', color: openRate > 20 ? '#10b981' : '#e2e8f0' },
  { label: 'Warm Leads', value: warmCount, color: warmCount > 0 ? '#f59e0b' : '#10b981' },
  { label: 'Booked', value: roi.total_booked || 0, color: (roi.total_booked || 0) > 0 ? '#10b981' : '#e2e8f0' },
];

const kpiHtml = kpis.map(k =>
  `<td style="text-align:center;padding:8px;">
    <div style="background:#1e293b;border:1px solid #334155;border-radius:8px;padding:14px 12px;">
      <div style="font-size:10px;color:#64748b;text-transform:uppercase;letter-spacing:0.05em;">${k.label}</div>
      <div style="font-size:24px;font-weight:700;color:${k.color};margin-top:4px;">${k.value}</div>
    </div>
  </td>`
).join('');

const pipelineHtml = ['pending','scored','contacted','replied','booked','unsubscribed']
  .map(s => `<span style="color:#94a3b8;font-size:13px;margin-right:16px;">${s}: <strong style="color:#e2e8f0;">${breakdown[s] || 0}</strong></span>`)
  .join('');

const warmSectionHtml = warmCount > 0
  ? `<div style="background:#1e293b;border:1px solid #334155;border-radius:8px;padding:16px;margin-bottom:24px;">
      <div style="font-size:11px;color:#64748b;text-transform:uppercase;letter-spacing:0.05em;margin-bottom:10px;">Warm Leads — top ${Math.min(warmCount, 5)} of ${warmCount}</div>
      ${warmTable}
    </div>`
  : `<div style="background:#134e2a;border:1px solid #166534;border-radius:8px;padding:16px;margin-bottom:24px;">
      <p style="color:#10b981;font-weight:600;margin:0;">No warm leads pending — inbox is clear.</p>
    </div>`;

const body_html = `<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="background:#0f172a;color:#e2e8f0;font-family:Arial,sans-serif;margin:0;padding:0;">
  <div style="max-width:620px;margin:0 auto;padding:32px 20px;">

    <h1 style="color:#818cf8;font-size:20px;margin:0 0 4px;">nrankai daily</h1>
    <p style="color:#64748b;font-size:13px;margin:0 0 24px;">${today}</p>

    <table style="width:100%;border-spacing:8px;border-collapse:separate;margin-bottom:24px;"><tr>${kpiHtml}</tr></table>

    <div style="background:#1e293b;border:1px solid #334155;border-radius:8px;padding:16px;margin-bottom:24px;">
      <div style="font-size:11px;color:#64748b;text-transform:uppercase;letter-spacing:0.05em;margin-bottom:10px;">Pipeline</div>
      <div>${pipelineHtml}</div>
    </div>

    ${warmSectionHtml}

    <div style="border-top:1px solid #1e293b;padding-top:20px;text-align:center;">
      <a href="https://api.nrankai.com/admin" style="background:#4f46e5;color:#fff;text-decoration:none;padding:11px 28px;border-radius:6px;font-size:14px;font-weight:600;display:inline-block;">Open Admin Dashboard</a>
      <p style="color:#334155;font-size:11px;margin-top:16px;">nrankai.com · automated daily digest</p>
    </div>

  </div>
</body>
</html>`;

return [{ json: { subject, body_html } }];
